// Start OAuth 2.0 Authorization Code Flow

// Step 1: Request Authorization Code
const clientID = 'your_client_id';
const redirectURI = 'https://your-redirect-uri';
const authEndpoint = 'https://authorization-server.com/oauth/authorize';

const authParams = `?client_id=${clientID}&redirect_uri=${encodeURIComponent(redirectURI)}&response_type=code`;

const authorizationUrl = authEndpoint + authParams;

window.location.href = authorizationUrl;

// Step 2: Exchange Authorization Code for Access Token
const tokenEndpoint = 'https://authorization-server.com/oauth/token';
const clientSecret = 'your_client_secret';
const authorizationCode = 'authorization_code_provided_by_server';

const tokenParams = {
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    Authorization: `Basic ${btoa(`${clientID}:${clientSecret}`)}`
  },
  body: `grant_type=authorization_code&code=${authorizationCode}&redirect_uri=${encodeURIComponent(redirectURI)}`
};

fetch(tokenEndpoint, tokenParams)
  .then(response => response.json())
  .then(data => {
    const accessToken = data.access_token;
    localStorage.setItem('accessToken', accessToken);
  });

// Access Token Stored in localStorage for API Requests

